import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How is credit card interest calculated?", a: "Credit card interest is usually calculated from the daily or monthly periodic rate based on your APR and the balance that remains unpaid." },
  { q: "How long does it take to pay off a credit card making minimum payments?", a: "It can take many years because minimum payments are often a small percentage of the balance, and a large part can go toward interest." },
  { q: "What is APR on a credit card?", a: "APR stands for annual percentage rate. It is the yearly interest rate used to calculate finance charges on unpaid balances." },
  { q: "How do you calculate minimum payment?", a: "A typical minimum payment is the larger of a fixed dollar amount or a percentage of the balance, plus any interest or fees required by the issuer." },
  { q: "What is the avalanche vs snowball debt payoff method?", a: "The avalanche method pays highest-interest debt first to save money. The snowball method pays smallest balances first to build momentum." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: digits });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const minimumPayment = (balance: number) => Math.max(25, balance * 0.02);

function payoff(balance: number, apr: number, payment: number) {
  let remaining = Math.max(0, balance);
  let totalInterest = 0;
  const monthlyRate = apr / 100 / 12;
  const schedule: { month: number; payment: number; interest: number; principal: number; balance: number }[] = [];
  for (let month = 1; month <= 1200 && remaining > 0.01; month++) {
    const interest = remaining * monthlyRate;
    if (payment <= interest && remaining > 0) return { months: Infinity, totalInterest: Infinity, totalPaid: Infinity, schedule };
    const paid = Math.min(payment, remaining + interest);
    const principal = paid - interest;
    remaining = Math.max(0, remaining - principal);
    totalInterest += interest;
    schedule.push({ month, payment: paid, interest, principal, balance: remaining });
  }
  return { months: schedule.length, totalInterest, totalPaid: balance + totalInterest, schedule };
}

export default function CreditCardCalculator() {
  useCurrencyVersion();
  const [balance, setBalance] = useState(5000);
  const [apr, setApr] = useState(20);
  const [payment, setPayment] = useState(200);
  const minPay = minimumPayment(balance);
  const result = useMemo(() => payoff(balance, apr, payment), [balance, apr, payment]);
  const comparison = [
    { label: "Minimum payment", amount: minimumPayment(5000) },
    { label: "$100", amount: 100 },
    { label: "$150", amount: 150 },
    { label: "$200", amount: 200 },
    { label: "$300", amount: 300 },
    { label: "Pay in full", amount: 5000 },
  ].map((row) => ({ ...row, data: payoff(5000, 20, row.amount) }));

  return (
    <>
      <SEOHead title="Free Credit Card Calculator Online - Calculate Payoff Time and Interest Instantly | CalcHive" description="Free online credit card calculator. Calculate how long it takes to pay off any credit card balance, total interest paid and minimum payment required instantly. 100% free, no signup required." canonical="/credit-card-calculator" keywords="free credit card calculator, credit card payoff calculator free online, credit card interest calculator free, minimum payment calculator free, credit card debt calculator free" category="Financial Calculators" breadcrumbName="Free Credit Card Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Credit Card Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate credit card payoff time, interest, and total cost from your balance, APR, and monthly payment.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Credit card balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate APR (%)</label><input type="number" value={apr} onChange={(e) => setApr(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Monthly payment</label><input type="number" value={payment} onChange={(e) => setPayment(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Months to Pay Off</p><p className="text-5xl sm:text-6xl font-black text-white">{Number.isFinite(result.months) ? result.months : "Never"}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{Number.isFinite(result.totalInterest) ? money(result.totalInterest) : "Increase payment"}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total paid</p><p className="text-lg font-extrabold text-foreground">{Number.isFinite(result.totalPaid) ? money(result.totalPaid) : "N/A"}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Minimum payment</p><p className="text-lg font-extrabold text-foreground">{money(minPay)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Credit Card Payoff Time and Interest for Free</h2><p className="text-muted-foreground leading-relaxed">This free credit card payoff calculator applies your APR each month, subtracts your payment, and shows how quickly the balance can reach zero.</p>
          <h2 className="text-2xl font-bold text-foreground">How Minimum Payments Keep You in Debt Longer</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Credit Card Payoff on $5,000 at 20% APR</caption><thead className="bg-muted/60"><tr>{["Monthly Payment", "Months to Pay Off", "Total Interest", "Total Paid"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.label}><td className="py-2.5 px-3 font-semibold">{row.label}</td><td className="py-2.5 px-3">{Number.isFinite(row.data.months) ? row.data.months : "Never"}</td><td className="py-2.5 px-3">{Number.isFinite(row.data.totalInterest) ? money(row.data.totalInterest) : "N/A"}</td><td className="py-2.5 px-3">{Number.isFinite(row.data.totalPaid) ? money(row.data.totalPaid) : "N/A"}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Credit Card Debt Calculator for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Payoff Timeline</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.slice(0, 120).map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/credit-card-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


